 31→/**
 32→ * Binding + additional contextual information
 33→ * Also defines equality over bindings.
 34→ * https://stackoverflow.com/questions/5453226/java-need-a-hash-map-where-one-supplies-a-function-to-do-the-hashing
 35→ */
 36→class MappableBinding(val binding: Binding, val screen: Screen) {
 37→    val isKey: Boolean get() = binding is KeyBinding
 38→
 39→    override fun equals(other: Any?): Boolean {
 40→        if (this === other) return true
 41→        if (other == null) return false
 42→
 43→        val otherBinding = (other as MappableBinding).binding
 44→        val bindingEquals = when {
 45→            binding is KeyCode && otherBinding is KeyCode -> binding.keycode == otherBinding.keycode && modifierEquals(otherBinding)
 46→            binding is UnicodeCharacter && otherBinding is UnicodeCharacter -> binding.unicodeCharacter == otherBinding.unicodeCharacter && modifierEquals(otherBinding)
 47→            binding is GestureInput && otherBinding is GestureInput -> binding.gesture == otherBinding.gesture
 48→            binding is AxisButtonBinding && otherBinding is AxisButtonBinding -> binding.axis == otherBinding.axis && binding.threshold == otherBinding.threshold
 49→            else -> false
 50→        }
 51→        if (!bindingEquals) {
 52→            return false
 53→        }
 54→
 55→        return screen.screenEquals(other.screen)
 56→    }
 57→
 58→    override fun hashCode(): Int {
 59→        // don't include the modifierKeys or mSide
 60→        val bindingHash = when (binding) {
 61→            is KeyCode -> binding.keycode
 62→            is UnicodeCharacter -> binding.unicodeCharacter
 63→            is GestureInput -> binding.gesture
 64→            is AxisButtonBinding -> hash(binding.axis.motionEventValue, binding.threshold.toInt())
 65→            else -> 0
 66→        }
 67→        return Objects.hash(bindingHash, screen.prefix)
 68→    }
 69→
 70→    private fun modifierEquals(otherBinding: KeyBinding): Boolean {
 71→        // equals allowing subclasses
 72→        val keys = otherBinding.modifierKeys
 73→        val thisKeys = (this.binding as KeyBinding).modifierKeys
 74→        if (thisKeys === keys) return true
 75→        return thisKeys.semiStructuralEquals(keys)
 76→
 77→        // allow subclasses to work - a subclass which overrides shiftMatches will return true on one of the tests
 78→    }
 79→
 80→    fun toDisplayString(context: Context): String {
 81→        return screen.toDisplayString(context, binding)
 82→    }
 83→
 84→    fun toPreferenceString(): String? {
 85→        return screen.toPreferenceString(binding)
 86→    }
