 70→    class KeyMap(
 71→        private val processor: ViewerCommand.CommandProcessor,
 72→        private val reviewerUI: ReviewerUi,
 73→        private val screenBuilder: (CardSide) -> Screen
 74→    ) {
 75→        val bindingMap = HashMap<MappableBinding, ViewerCommand>()
 76→
 77→        @Suppress("UNUSED_PARAMETER")
 78→        fun onKeyDown(keyCode: Int, event: KeyEvent?): Boolean {
 79→            var ret = false
 80→            val bindings = possibleKeyBindings(event!!)
 81→            val side = fromAnswer(reviewerUI.isDisplayingAnswer)
 82→            for (b in bindings) {
 83→                val binding = MappableBinding(b, screenBuilder(side))
 84→                val command = bindingMap[binding] ?: continue
 85→                ret = ret or processor.executeCommand(command, fromGesture = null)
 86→            }
 87→            return ret
 88→        }
 89→
 90→        operator fun set(key: MappableBinding, value: ViewerCommand) {
 91→            bindingMap[key] = value
 92→        }
