122→        private fun fromTapCorners(height: Int, width: Int, posX: Float, posY: Float): Gesture {
123→            val heightSegment = height / 3.0
124→            val widthSegment = width / 3.0
125→            val wSector = clamp(posX / widthSegment)
126→            val hSector = clamp(posY / heightSegment)
127→            return when (wSector) {
128→                TriState.LOW -> when (hSector) {
129→                    TriState.LOW -> Gesture.TAP_TOP_LEFT
130→                    TriState.MID -> Gesture.TAP_LEFT
131→                    TriState.HIGH -> Gesture.TAP_BOTTOM_LEFT
132→                }
133→                TriState.MID -> when (hSector) {
134→                    TriState.LOW -> Gesture.TAP_TOP
135→                    TriState.MID -> Gesture.TAP_CENTER
136→                    TriState.HIGH -> Gesture.TAP_BOTTOM
137→                }
138→                TriState.HIGH -> when (hSector) {
139→                    TriState.LOW -> Gesture.TAP_TOP_RIGHT
140→                    TriState.MID -> Gesture.TAP_RIGHT
141→                    TriState.HIGH -> Gesture.TAP_BOTTOM_RIGHT
142→                }
143→            }
144→        }
