 28→class GestureMapper {
 29→    var tapGestureMode = TapGestureMode.NINE_POINT
 30→        private set
 31→    private var swipeMinDistance = -1
 32→    private var swipeThresholdVelocity = -1
 33→    fun init(preferences: SharedPreferences) {
 34→        val sensitivity = preferences.getInt("swipeSensitivity", 100)
 35→        tapGestureMode = fromPreference(preferences)
 36→
 37→        // ViewConfiguration can be used statically but it must be initialized during Android application lifecycle
 38→        // Else, when Robolectric executes in the CI it accesses AnkiDroidApp.getInstance before it exists #9173
 39→        if (VIEW_CONFIGURATION == null) {
 40→            // Set good default values for swipe detection
 41→            VIEW_CONFIGURATION = ViewConfiguration.get(AnkiDroidApp.instance)
 42→            DEFAULT_SWIPE_MIN_DISTANCE = VIEW_CONFIGURATION!!.scaledPagingTouchSlop
 43→            DEFAULT_SWIPE_THRESHOLD_VELOCITY = VIEW_CONFIGURATION!!.scaledMinimumFlingVelocity
 44→        }
 45→        if (sensitivity != 100) {
 46→            val sens = 100.0f / sensitivity
 47→            swipeMinDistance = (DEFAULT_SWIPE_MIN_DISTANCE * sens + 0.5f).toInt()
 48→            swipeThresholdVelocity = (DEFAULT_SWIPE_THRESHOLD_VELOCITY * sens + 0.5f).toInt()
 49→        } else {
 50→            swipeMinDistance = DEFAULT_SWIPE_MIN_DISTANCE
 51→            swipeThresholdVelocity = DEFAULT_SWIPE_THRESHOLD_VELOCITY
 52→        }
 53→    }
 54→
 55→    fun gesture(
 56→        dx: Float,
 57→        dy: Float,
 58→        velocityX: Float,
 59→        velocityY: Float,
 60→        isSelecting: Boolean,
 61→        isXScrolling: Boolean,
 62→        isYScrolling: Boolean
 63→    ): Gesture? {
 64→        try {
 65→            if (abs(dx) > abs(dy)) {
 66→                // horizontal swipe if moved further in x direction than y direction
 67→                if (dx > swipeMinDistance && abs(velocityX) > swipeThresholdVelocity && !isXScrolling && !isSelecting) {
 68→                    return Gesture.SWIPE_RIGHT
 69→                } else if (dx < -swipeMinDistance && abs(velocityX) > swipeThresholdVelocity && !isXScrolling && !isSelecting) {
 70→                    return Gesture.SWIPE_LEFT
 71→                }
 72→            } else {
 73→                // otherwise vertical swipe
 74→                if (dy > swipeMinDistance && abs(velocityY) > swipeThresholdVelocity && !isYScrolling) {
 75→                    return Gesture.SWIPE_DOWN
 76→                } else if (dy < -swipeMinDistance && abs(velocityY) > swipeThresholdVelocity && !isYScrolling) {
 77→                    return Gesture.SWIPE_UP
 78→                }
 79→            }
 80→        } catch (e: Exception) {
 81→            Timber.e(e, "onFling Exception")
 82→        }
 83→        return null
 84→    }
 85→
 86→    fun gesture(height: Int, width: Int, posX: Float, posY: Float): Gesture? {
 87→        return if (width == 0 || height == 0) {
 88→            null
 89→        } else {
 90→            when (tapGestureMode) {
 91→                TapGestureMode.FOUR_POINT -> fromTap(height, width, posX, posY)
 92→                TapGestureMode.NINE_POINT -> fromTapCorners(height, width, posX, posY)
 93→            }
 94→        }
 95→    }
 96→
 97→    private enum class TriState {
 98→        LOW, MID, HIGH
 99→    }
100→
101→    companion object {
102→        private var VIEW_CONFIGURATION: ViewConfiguration? = null
103→        private var DEFAULT_SWIPE_MIN_DISTANCE = 0
104→        private var DEFAULT_SWIPE_THRESHOLD_VELOCITY = 0
105→        private fun fromTap(height: Int, width: Int, posX: Float, posY: Float): Gesture {
106→            val gestureIsRight = posY > height * (1 - posX / width)
107→            return if (posX > posY / height * width) {
108→                if (gestureIsRight) {
109→                    Gesture.TAP_RIGHT
110→                } else {
111→                    Gesture.TAP_TOP
112→                }
113→            } else {
114→                if (gestureIsRight) {
115→                    Gesture.TAP_BOTTOM
116→                } else {
117→                    Gesture.TAP_LEFT
118→                }
119→            }
120→        }
121→
122→        private fun fromTapCorners(height: Int, width: Int, posX: Float, posY: Float): Gesture {
123→            val heightSegment = height / 3.0
124→            val widthSegment = width / 3.0
125→            val wSector = clamp(posX / widthSegment)
126→            val hSector = clamp(posY / heightSegment)
127→            return when (wSector) {
128→                TriState.LOW -> when (hSector) {
129→                    TriState.LOW -> Gesture.TAP_TOP_LEFT
130→                    TriState.MID -> Gesture.TAP_LEFT
131→                    TriState.HIGH -> Gesture.TAP_BOTTOM_LEFT
132→                }
133→                TriState.MID -> when (hSector) {
134→                    TriState.LOW -> Gesture.TAP_TOP
135→                    TriState.MID -> Gesture.TAP_CENTER
136→                    TriState.HIGH -> Gesture.TAP_BOTTOM
137→                }
138→                TriState.HIGH -> when (hSector) {
139→                    TriState.LOW -> Gesture.TAP_TOP_RIGHT
140→                    TriState.MID -> Gesture.TAP_RIGHT
141→                    TriState.HIGH -> Gesture.TAP_BOTTOM_RIGHT
142→                }
143→            }
144→        }
145→
146→        /**
147→         * clamps the value from LOW-MID-HIGH
148→         *
149→         * @param value number between 0 and 3
150→         * @return
151→         * [TriState.HIGH] if `>=` 2.
152→         *
153→         * [TriState.MID] if between 1 and 2
154→         *
155→         * [TriState.LOW] if `<` 1
156→         */
157→        private fun clamp(value: Double): TriState {
158→            val valueFloor = floor(value)
159→            if (valueFloor >= 2) {
160→                return TriState.HIGH
161→            }
162→            return if (valueFloor < 1) {
163→                TriState.LOW
164→            } else {
165→                TriState.MID
166→            }
167→        }
168→    }
